INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0601104A$$, 2026, $$This Program Element (PE) fosters university and industry based research to provide a scientific foundation for enabling technologies for future force capabilities.
Broadly, the work in this PE falls into the categories of Collaborative Technology Alliances / Collaborative Research Alliances (CTAs/CRAs), University Centers of
Excellence (COE), University Affiliated Research Centers (UARCs), Army-sponsored educational outreach, and Army investments at international academic and
industrial partners. The Army formed CTAs to leverage large investments by the commercial sector in basic research areas that are of great interest to the Army. CTAs
are industry-led partnerships between industry, academia, and the Army Futures Command to incorporate the practicality of industry, the expansion of the boundaries of
knowledge from universities, and Army scientists to shape, mature, and transition technology relevant to the Army mission. CRAs are academia-led partnerships, which
leverage the cutting-edge innovation found in the academic environment. The COEs focus on expanding the frontiers of knowledge in research areas where the Army
has enduring needs, and couples state-of-the-art research programs at academic institutions with broad-based graduate education programs to increase the supply of
scientists and engineers in automotive and rotary wing technology. Also included are Army Educational Outreach Program (AEOP) and activities to stimulate interest in
science, math, and technology among middle and high school students. This PE includes support for basic research at three Army UARCs, which have been created
to exploit opportunities to advance new capabilities through a sustained long- term multidisciplinary effort. The Institute for Soldier Nanotechnologies focuses on Soldier
protection by emphasizing revolutionary materials research for advanced Soldier protection and survivability. The Institute for Collaborative Biotechnologies focuses
on enabling network centric-technologies, and broadening the Army's use of biotechnology for the development of bio-inspired materials, sensors, and information
processing. The Institute for Creative Technologies is a partnership with academia and the entertainment and gaming industries to leverage innovative research and
